import React, { useEffect, useState } from 'react';
import api from '../api/axiosConfig';
import { useTheme } from '../context/ThemeContext'; 
import ReactMarkdown from 'react-markdown';
import { Trash2, Download, Archive, Calendar, ShieldCheck, Eye, X, BarChart3, AlignLeft } from 'lucide-react';
import toast from 'react-hot-toast';

const VaultPage = () => {
  const { isDark } = useTheme(); 
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState(null);

  const fetchHistory = async () => {
    try {
      const res = await api.get('/portfolio/history');
      setHistory(res.data);
    } catch (err) {
      toast.error("VAULT_SYNC_ERROR: UNABLE_TO_REACH_DATABASE");
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("PERMANENT_WIPE: This node data will be destroyed. Proceed?")) return;
    try {
      await api.delete(`/portfolio/${id}`);
      setHistory(prev => prev.filter(item => item.id !== id));
      toast.success("DATA_PURGE_SUCCESSFUL");
    } catch (err) { 
      toast.error("WIPE_FAILURE: DATA_PROTECTED_BY_SYSTEM"); 
    }
  };

  const handleDownload = async (item) => {
    try {
      const response = await api.post('/portfolio/export', item, { responseType: 'blob' });
      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `Finify_Strategy_${item.id}.pdf`);
      document.body.appendChild(link);
      link.click();
      link.remove();
    } catch (err) { 
      toast.error("EXPORT_FAILED: GENERATION_ERROR"); 
    }
  };

  useEffect(() => { 
    fetchHistory(); 
  }, []);

  if (loading) return <div style={centerStyle}>SYNCHRONIZING_STRATEGY_VAULT...</div>;

  return (
    <div className="reveal-node" style={containerStyle}>
      {/* ── Page Header ── */}
      <div style={headerRow}>
        <h2 style={headerStyle}>
            <Archive size={40} color="var(--accent-primary)"/> STRATEGY_VAULT
        </h2>
        <div style={vaultBadge}>
            <BarChart3 size={20} /> {history.length} ACTIVE_NODES
        </div>
      </div>
      
      {/* ── Strategy Grid ── */}
      <div style={listStyle}>
        {history.map((item) => (
          <div key={item.id} className="vault-card" style={cardStyle}>
            <div style={cardMeta}>
              <div style={{ display: 'flex', gap: '30px' }}>
                <span style={dateTag}><Calendar size={20}/> {new Date(item.created_at).toLocaleDateString()}</span>
                <span style={riskTag}><ShieldCheck size={20}/> RISK_EXPOSURE: {item.risk_score}</span>
              </div>
              <div style={cardActions}>
                <button onClick={() => setSelectedItem(item)} style={iconBtn} title="View Details"><Eye size={32}/></button>
                <button onClick={() => handleDownload(item)} style={iconBtn} title="Export PDF"><Download size={32}/></button>
                <button onClick={() => handleDelete(item.id)} style={deleteBtn} title="Purge Node"><Trash2 size={32}/></button>
              </div>
            </div>

            <h4 style={titleStyle}>{item.goal}</h4>

            <div style={sectionBlock}>
              <p style={labelSmall}><AlignLeft size={16} style={{marginRight:'12px'}}/> STRATEGIC_SUMMARY</p>
              <div className="markdown-vault">
                <ReactMarkdown>{item.summary}</ReactMarkdown>
              </div>
            </div>
          </div>
        ))}

        {history.length === 0 && (
          <div style={emptyState}>NO_DATA_FOUND: INITIALIZE_STRATEGY_IN_DASHBOARD</div>
        )}
      </div>

      {/* ── Detail Modal (Description) ── */}
      {selectedItem && (
        <div style={modalOverlay(isDark)}>
          <div style={modalContent}>
            <div style={modalHeader}>
              <span style={modalId}>NODE_DATA // SYNC_ID_{selectedItem.id}</span>
              <button onClick={() => setSelectedItem(null)} style={closeBtn}><X size={36}/></button>
            </div>
            <div style={modalBody}>
              <h3 style={modalTitle}>{selectedItem.goal}</h3>
              <div style={modalSectionStyle}>
                <p style={modalLabel}><AlignLeft size={20} style={{marginRight:'15px'}}/> AGENTIC_RATIONALE</p>
                <div className="markdown-vault">
                    <ReactMarkdown>{selectedItem.rationale}</ReactMarkdown>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      <style>{`
        .markdown-vault h1, .markdown-vault h2 { color: var(--accent-primary); font-size: 1.4rem; margin-top: 2rem; text-transform: uppercase; font-weight: 900; }
        .markdown-vault p { color: var(--text-primary); font-size: 1.2rem; line-height: 1.9; margin-bottom: 1.5rem; }
        .vault-card { transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1); }
        .vault-card:hover { border-color: var(--accent-primary) !important; transform: translateY(-8px); box-shadow: 0 20px 50px var(--shadow-color); }
        .reveal-node { animation: fadeIn 0.5s ease-out; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(20px); } to { opacity: 1; transform: translateY(0); } }
      `}</style>
    </div>
  );
};

/* --- Visual Styles (Big Text + OLED Dark Mode) --- */
const containerStyle = { padding: '5rem 2rem', maxWidth: '1400px', margin: '0 auto' };

const headerRow = { 
    display: 'flex', 
    justifyContent: 'space-between', 
    alignItems: 'center', 
    marginBottom: '5rem', 
    borderBottom: '2px solid var(--surface-border)', 
    paddingBottom: '3rem' 
};

const headerStyle = { 
    display: 'flex', 
    alignItems: 'center', 
    gap: '25px', 
    fontSize: '2.8rem', 
    fontWeight: 900, 
    color: 'var(--text-primary)', 
    margin: 0,
    letterSpacing: '-0.02em'
};

const vaultBadge = { 
    fontSize: '1.1rem', 
    color: 'var(--accent-primary)', 
    fontWeight: 900, 
    background: 'rgba(16,185,129,0.1)', 
    padding: '12px 24px', 
